int numJewelsInStones(char* jewels, char* stones) {
    int seen[256]={0}; for(;*jewels;jewels++) seen[(unsigned char)*jewels]=1;
    int ans=0; for(;*stones;stones++) if(seen[(unsigned char)*stones]) ans++; return ans;
}
